def average_color(colors):
    total_r, total_g, total_b = 0, 0, 0
    for r, g, b in colors:
        total_r += r
        total_g += g
        total_b += b
    avg_r = total_r // len(colors)
    avg_g = total_g // len(colors)
    avg_b = total_b // len(colors)
    return (avg_r, avg_g, avg_b)
